// Formatar dados para visualização
const items = $input.all();
const memorias = items.map(item => {
  const d = item.json;
  const data = new Date(d.created_at);
  const dataFormatada = data.toLocaleDateString('pt-PT') + ' ' + data.toLocaleTimeString('pt-PT', {hour: '2-digit', minute: '2-digit'});

  return {
    json: {
      '📝 Título': d.title || 'Sem título',
      '📂 Categoria': d.category || 'geral',
      '📄 Descrição': (d.description || '').substring(0, 100),
      '🔧 Skill Origem': d.origin_skill || 'desconhecido',
      '📅 Data': dataFormatada,
      '🆔 ID': d.id ? d.id.substring(0, 8) + '...' : '',
    }
  };
});

return memorias;

// Estatísticas gerais
const items = $('Buscar Memórias').all();
const total = items.length;

// Contar por categoria
const categorias = {};
items.forEach(item => {
  const cat = item.json.category || 'sem_categoria';
  categorias[cat] = (categorias[cat] || 0) + 1;
});

// Contar por skill
const skills = {};
items.forEach(item => {
  const skill = item.json.origin_skill || 'desconhecido';
  skills[skill] = (skills[skill] || 0) + 1;
});

// Última memória
const ultima = items[0]?.json;
const ultimaData = ultima ? new Date(ultima.created_at).toLocaleDateString('pt-PT') : 'N/A';

return [{
  json: {
    '📊 DASHBOARD DE MEMÓRIAS': '═══════════════════',
    '🔢 Total de Registos': total,
    '📂 Categorias': Object.entries(categorias).map(([k,v]) => `${k}: ${v}`).join(' | '),
    '🔧 Skills Ativas': Object.entries(skills).map(([k,v]) => `${k}: ${v}`).join(' | '),
    '📅 Último Registo': ultimaData,
    '📝 Último Título': ultima?.title || 'N/A',
  }
}];
